mapper.select:
SELECT notice_id as noticeId, title, content, created_at AS createdAt
FROM notice 
WHERE notice_id = #{noticeId}

SELECT name AS name, description AS description
FROM subject
WHERE name = #{type}

SELECT user_id AS userId
FROM user
WHERE user_id = #{id} AND password = #{pw}

mapper.update:
UPDATE user 
SET PASSWORD = #{updatePw} 
WHERE user_id = #{id} AND PASSWORD = #{currentPw}

mapper.select:
SELECT album_id, lecture_id, title, description, created_at FROM album
WHERE title LIKE CONCAT('%', #{keyword}, '%')
ORDER BY created_at DESC LIMIT #{startRow}, #{rowPerPage}
